import React, { useEffect, useState } from 'react';
import api from '../../services/api';

export default function Templates() {
  const [templates, setTemplates] = useState([]);

  useEffect(() => {
    api.get('/templates').then(r => setTemplates(r.data)).catch(() => {});
  }, []);

  return (
    <div className="p-8">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Templates</h1>
          <p className="text-gray-500 mt-1">Templates de CV disponibles pour la transformation</p>
        </div>
        <button className="bg-gray-100 text-gray-600 px-4 py-2 rounded-lg text-sm hover:bg-gray-200 transition">
          + Demander un nouveau template
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {templates.map(t => (
          <div key={t.id} className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden hover:shadow-md transition">
            {/* Preview */}
            <div className="h-48 bg-gradient-to-br from-blue-50 to-blue-100 flex items-center justify-center">
              {t.pdfPreviewPath ? (
                <iframe
                  src={`http://localhost:8080/api/templates/${t.id}/preview`}
                  className="w-full h-full"
                  title={t.name}
                />
              ) : (
                <div className="text-center">
                  <p className="text-5xl mb-2">📋</p>
                  <p className="text-blue-400 text-sm font-medium">{t.name}</p>
                </div>
              )}
            </div>
            <div className="p-4">
              <h3 className="font-semibold text-gray-900">{t.name}</h3>
              <p className="text-gray-400 text-sm mt-1">{t.description || 'Template officiel Tritux'}</p>
              <div className="mt-3 flex gap-2">
                <a
                  href={`http://localhost:8080/api/templates/${t.id}/download`}
                  className="text-xs bg-blue-50 text-blue-700 px-3 py-1.5 rounded-lg hover:bg-blue-100 transition"
                >
                  Télécharger
                </a>
              </div>
            </div>
          </div>
        ))}

        {templates.length === 0 && (
          <div className="col-span-3 text-center py-20 text-gray-300">
            <p className="text-4xl mb-2">📋</p>
            <p>Aucun template disponible</p>
          </div>
        )}
      </div>
    </div>
  );
}
